 49→// ── Toast Notification System ──
 50→interface Toast {
 51→  id: string;
 52→  type: 'success' | 'error' | 'info';
 53→  message: string;
 54→}
 55→
 56→const ToastContext = createContext<{
 57→  showToast: (type: Toast['type'], message: string) => void;
 58→}>({ showToast: () => {} });
 59→
 60→export const useToast = () => useContext(ToastContext);
 61→
 62→const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
 63→  return (
 64→    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-2.5 pointer-events-none">
 65→      {toasts.map((toast) => {
 66→        const styles = {
 67→          success: 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300',
 68→          error: 'bg-red-500/15 border-red-500/30 text-red-300',
 69→          info: 'bg-blue-500/15 border-blue-500/30 text-blue-300',
 70→        };
 71→        const icons = { success: '✓', error: '✕', info: 'ℹ' };
 72→        return (
 73→          <div
 74→            key={toast.id}
 75→            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-2xl shadow-black/40 animate-in slide-in-from-right fade-in duration-300 ${styles[toast.type]}`}
 76→            onClick={() => onRemove(toast.id)}
 77→          >
 78→            <span className="text-sm font-bold">{icons[toast.type]}</span>
 79→            <span className="text-sm font-medium">{toast.message}</span>
 80→          </div>
